const gdList = {{node:search_node_AHtHRmqi.data.data}};
const filterDraft = {{workflowparams:filter_draft}};
const source = {{workflowparams:source}};
const unCompletedGD = gdList.filter((gd) => gd.gd_status !== 'Completed');

// source = 'auto' is GDheadWorkflow calling us right after it saved the GD as Completed, so
// there is no user to answer a prompt. It must never take an error end-node either: this runs
// nested inside the GD workflow, and a thrown 401 there would surface as a failed GD save even
// though the GD is already committed. A non-Completed GD is simply filtered out downstream
// (search_node_bOF3TVA2) and reported as 'skipped'.
if (unCompletedGD.length > 0 && filterDraft == 'no' && source !== 'auto') {
  return {
    status: 'Failed',
    message: 'Selected Goods Deliveries with Draft/Created status cannot be converted.<br><br> If proceed, it will filter out the draft/created GD.'
  }
} else {
  return {
    status: 'Success',
    message: ''
  }
}

const gdList = {{node:search_node_AHtHRmqi.data.data}};

// Use flatMap to combine all so_id arrays into one flat array
const soIDs = gdList.flatMap((gd) => gd.so_id || []);

// If you want to remove duplicates
const uniqueSoIDs = [...new Set(soIDs)];

return {
  uniqueSoIDs,
};

return {
  message: 'Selected Goods Delivery(s) already has existing Sales Invoice and cannot be converted.'
}

const gdRaw = {{node:search_node_bOF3TVA2.data.data}} || [];
const gdList = Array.isArray(gdRaw) ? gdRaw : [gdRaw];
const isMultiple = {{workflowparams:is_multiple}}

// organizationId scopes the SI number-rule lookup (get_node_yDMG0Sab). It used to read the
// {{global:firstLvDeptId}} session global, which is not reliable when this workflow runs nested
// under GDheadWorkflow (itself possibly driven by PickingProcessWorkflow). The GD row is the
// authoritative source of the org, so derive it from there.
const organizationId = gdList.length > 0 ? gdList[0].organization_id : "0";

// No Completed GD survived the filter -- nothing to invoice. Not an error: the empty siList is
// caught by if_no_si downstream, which reports it as 'skipped' rather than taking an error node.
if (gdList.length === 0) {
  return { status: "Empty", code: 200, message: "", organizationId: organizationId };
}

let customers = new Set(gdList.map((gd) => gd.customer_name));
let plants = new Set(gdList.map((gd) => gd.plant_id));
if (customers.size > 1 && isMultiple === "single") {
  return {
    status: "Failed",
    code: 403,
    message:
      "All selected Goods Delivery(s) must be from the same customer to create a single Sales Invoice.",
    organizationId: organizationId,
  };
} else if (plants.size > 1 && isMultiple === "single") {
  return {
    status: "Failed",
    code: 403,
    message:
      "All selected Goods Delivery(s) must be from the same plant to create a single Sales Invoice.",
    organizationId: organizationId,
  };
} else {
  return {
    status: "Success",
    code: 200,
    message: "",
    organizationId: organizationId,
  };
}

const gdList = {{node:search_node_AHtHRmqi.data.data}};

// Get all so_line_item_id from table_gd arrays
const soLineIds = gdList.flatMap((gd) => {
  // Check if table_gd exists and is an array
  if (gd.table_gd && Array.isArray(gd.table_gd)) {
    return gd.table_gd.map((item) => item.so_line_item_id);
  }
  return [];
}).filter(id => id !== null && id !== undefined && id !== '');

// Remove duplicates if needed
const uniqueSoLineIds = [...new Set(soLineIds)];

return {
  uniqueSoLineIds
};

const gdRaw = {{node:search_node_bOF3TVA2.data.data}} || [];
const gdList = Array.isArray(gdRaw) ? gdRaw : [gdRaw];
const isMultiple = {{workflowparams:is_multiple}};
const convertTo = {{workflowparams:convert_to}};
const source = {{workflowparams:source}};
const autoPi = {{workflowparams:auto_pi}};
const docFormatRaw = {{node:get_node_yDMG0Sab.data.data}};
const soLineItemList = {{node:search_node_r3bnMaWy.data.data}} || [];
const soList = {{node:search_node_Ivek0yYx.data.data}} || [];
let siList = [];

// 'auto' = GDheadWorkflow created this SI itself right after completing the GD.
// It runs nested inside the GD workflow, so SI_SAVE must never take one of its ERROR end-nodes
// (406 required / 407 zero qty / 410 qty exceeds available): those throw, and the throw would
// surface as a failed GD save even though the GD is already committed. page_status "Convert"
// already makes the credit-limit codes (408/409) unreachable -- SI_SAVE downgrades to Draft
// instead -- so the remaining job here is to guarantee we never hand it an invalid payload:
//   - skip SO lines with nothing left to invoice   -> cannot trigger 407
//   - never invoice more than the SO line has left -> cannot trigger 410
const isAuto = source === "auto";

const docFormat = Array.isArray(docFormatRaw) ? docFormatRaw[0] : docFormatRaw;
const roundQty = (value) => Math.round((parseFloat(value) || 0) * 1000) / 1000;
const scalar = (v) => (Array.isArray(v) ? v[0] : v);

const mapLineItem = (
  gdItem,
  soLineItem,
  record,
  index,
  soData,
  plantID,
  invoiceQty,
) => {
  // invoiceQty is what we actually bill: gd_qty for a normal convert, and gd_qty capped to the
  // SO line's remaining invoiceable quantity on the auto path.
  const gdQuantity = invoiceQty;
  const soQuantity = parseFloat(soLineItem.so_quantity) || 1;
  const unitPrice = parseFloat(soLineItem.so_item_price) || 0;
  let discount = parseFloat(soLineItem.so_discount) || 0;
  const discountAmount = parseFloat(soLineItem.so_discount_amount) || 0;
  const taxAmount = parseFloat(soLineItem.so_tax_amount) || 0;
  const totalAmount = parseFloat(soLineItem.so_amount) || 0;

  // Recalculate amounts based on the invoiced quantity
  const ratio = soQuantity > 0 ? gdQuantity / soQuantity : 0;
  const recalculatedGross = unitPrice * gdQuantity;
  const recalculatedDiscountAmount = discountAmount * ratio;
  const recalculatedTaxAmount = taxAmount * ratio;
  const recalculatedAmount = totalAmount * ratio;

  if (soLineItem.so_discount_uom && soLineItem.so_discount_uom === "Amount") {
    discount = discount * ratio;
  }

  const lineItemPromise = {
    tax_amount: recalculatedTaxAmount.toFixed(4),
    so_order_quantity: soQuantity.toFixed(3),
    plant_id: plantID,
    si_discount: discount.toFixed(4),
    available_inv_qty: (
      parseFloat(soLineItem.so_quantity || 0) -
      parseFloat(soLineItem.invoice_qty || 0)
    ).toFixed(3),
    agent_id: soLineItem.sales_person_id,
    discount_amount: recalculatedDiscountAmount.toFixed(4),
    invoice_qty: gdQuantity.toFixed(3),
    invoice_qty_uom_id: gdItem.good_delivery_uom_id || soLineItem.so_item_uom,
    so_order_uom_id: soLineItem.so_item_uom,
    material_desc: soLineItem.so_desc,
    more_desc: gdItem.more_desc,
    si_discount_uom_id: soLineItem.so_discount_uom,
    item_category_id: gdItem.item_category_id,
    payment_term_id: soLineItem.payment_term_id,
    line_so_id: soData.id,
    material_name: gdItem.material_name,
    si_amount: recalculatedAmount.toFixed(4),
    gross: recalculatedGross.toFixed(4),
    so_line_id: soLineItem.id,
    si_tax_inclusive: soLineItem.so_tax_inclusive,
    si_tax_rate_id: soLineItem.so_tax_preference,
    tax_percent: soLineItem.so_tax_percentage,
    unit_price: unitPrice.toFixed(4),
    good_delivery_quantity: gdQuantity.toFixed(3),
    line_so_no: soData.so_no,
    material_id: gdItem.material_id,
    customer_id: gdItem.customer_id,
    line_index: index + 1,
    area_id: gdItem.area_id,
    line_remark_3: gdItem.line_remark_3,
    line_remark_2: gdItem.line_remark_2,
    line_remark_1: gdItem.line_remark_1,
    tariff_id: gdItem.tariff_id,
    // Add GD reference
    line_gd_no: record.delivery_no,
    gd_line_id: gdItem.id,
    line_gd_id: record.id,
    exchange_rate:
      parseFloat(soData.exchange_rate) === 0
        ? 1
        : parseFloat(soData.exchange_rate),
    exchange_rate_currency: soData.exchange_rate_currency,
    custom_fields: gdItem.custom_fields,
  };

  return lineItemPromise;
};

const mapHeaderData = (
  record,
  lineItemPromise,
  soNoDisplay,
  soID,
  gdNoDisplay,
  gdID,
  totals,
) => {
  const data = {
    page_status: "Convert",
    si_status: convertTo === "draft" ? "Draft" : "Completed",
    invoice_type: "Credit",
    plant_id: record.plant_id,
    so_no_display: soNoDisplay,
    gd_no_display: gdNoDisplay,
    so_id: soID,
    gd_id: gdID,
    customer_id: record.customer_name,
    currency_code: record.currency_code,
    si_billing_address: record.gd_billing_address,
    si_shipping_address: record.gd_shipping_address,
    sales_invoice_no: convertTo === "draft" ? "draft" : "issued",
    sales_invoice_no_type: docFormat ? docFormat.id : -9999,
    sales_invoice_date: new Date().toISOString().split("T")[0],
    sales_person_id: scalar(record.sales_person),
    si_payment_term_id: lineItemPromise[0].payment_term_id,
    exchange_rate_currency: lineItemPromise[0].exchange_rate_currency,
    exchange_rate: lineItemPromise[0].exchange_rate,
    exchange_rate_myr: "MYR",
    si_description: "Sales",
    posted_date: "",
    si_area_id: record.gd_area_id || "",
    posted_status: convertTo === "draft" ? "" : "Unposted",
    organization_id: record.organization_id,
    acc_integration_type: record.acc_integration_type,
    previous_status: "",
    customer_credit_limit: record.customer_credit_limit,
    overdue_limit: record.overdue_limit,
    outstanding_balance: record.outstanding_balance,
    overdue_inv_total_amount: record.overdue_inv_total_amount,
    is_accurate: record.is_accurate,
    table_si: lineItemPromise,
    total_gross_currency: record.currency_code,
    total_discount_currency: record.currency_code,
    total_tax_currency: record.currency_code,
    total_amount_currency: record.currency_code,
    total_amount_myr: "MYR",
    invoice_subtotal: totals.invoice_subtotal,
    invoice_total_discount: totals.invoice_total_discount,
    invoice_taxes_amount: totals.invoice_taxes_amount,
    invoice_total: totals.invoice_total,
    myr_total_amount: totals.myr_total_amount,
    tnc: record.order_tnc,
    payment_term: record.order_payment_details,
    delivery_term: record.order_delivery_term,
    remarks: record.order_remark,
    remarks2: record.order_remark2,
    remarks3: record.order_remark3,
    remarks4: record.order_remark4,
    remarks5: record.order_remark5,
    billing_address_name: record.billing_address_name,
    billing_address_phone: record.billing_address_phone,
    billing_address_line_1: record.billing_address_line_1,
    billing_address_line_2: record.billing_address_line_2,
    billing_address_line_3: record.billing_address_line_3,
    billing_address_line_4: record.billing_address_line_4,
    billing_address_city: record.billing_address_city,
    billing_postal_code: record.billing_postal_code,
    billing_address_state: record.billing_address_state,
    billing_address_country: record.billing_address_country,
    billing_attention: record.billing_attention,
    billing_address_fax: record.billing_address_fax,
    shipping_address_name: record.shipping_address_name,
    shipping_address_phone: record.shipping_address_phone,
    shipping_address_line_1: record.shipping_address_line_1,
    shipping_address_line_2: record.shipping_address_line_2,
    shipping_address_line_3: record.shipping_address_line_3,
    shipping_address_line_4: record.shipping_address_line_4,
    shipping_address_city: record.shipping_address_city,
    shipping_postal_code: record.shipping_postal_code,
    shipping_address_state: record.shipping_address_state,
    shipping_address_country: record.shipping_address_country,
    shipping_attention: record.shipping_attention,
    shipping_address_fax: record.shipping_address_fax,
  };

  // SI_SAVE pre-gates internal-trading SIs with pi_confirm 411 and saves NOTHING until the caller
  // answers it. Nobody here answered it before, so completing an internal-trading GD produced no
  // invoice at all while still reporting success. Both callers now answer it:
  //   - auto: nobody to ask, so pre-confirm. The buyer org already opted in through
  //     internal_trading_setup.auto_create_pi, which is what really decides if a PI gets created.
  //   - convert: handleConvertGDtoSI asks the user and passes the answer down as auto_pi.
  // Harmless when nothing is internally linked -- the gate never arms and both flags are ignored.
  if (isAuto || autoPi === "confirmed") {
    data.auto_pi_confirmed = true;
  } else if (autoPi === "skip") {
    data.auto_pi_skip = true;
  }

  return data;
};

// Helper function to calculate totals from GD lines
const calculateTotalsFromGdLines = (gdLines) => {
  let totals = {
    invoice_subtotal: 0,
    invoice_total_discount: 0,
    invoice_taxes_amount: 0,
    invoice_total: 0,
    myr_total_amount: 0,
  };

  for (const gdLine of gdLines) {
    totals.invoice_subtotal += parseFloat(gdLine.recalculated_gross) || 0;
    totals.invoice_total_discount +=
      parseFloat(gdLine.recalculated_discount_amount) || 0;
    totals.invoice_taxes_amount +=
      parseFloat(gdLine.recalculated_tax_amount) || 0;
    totals.invoice_total += parseFloat(gdLine.recalculated_amount) || 0;
    totals.myr_total_amount += parseFloat(gdLine.myr_amount) || 0;
  }

  totals.invoice_subtotal = totals.invoice_subtotal.toFixed(4);
  totals.invoice_total_discount = totals.invoice_total_discount.toFixed(4);
  totals.invoice_taxes_amount = totals.invoice_taxes_amount.toFixed(4);
  totals.invoice_total = totals.invoice_total.toFixed(4);
  totals.myr_total_amount = totals.myr_total_amount.toFixed(4);

  return totals;
};

// Helper function to find matching SO line item
const findSoLineItem = (gdItem, soLineItemList) => {
  return soLineItemList.find((item) => item.id === gdItem.so_line_item_id);
};

const findSOData = (gdItem, soList) => {
  return soList.find((item) => item.id === gdItem.line_so_id);
};

// Process GD list and create SI
const processGdList = (gdListData) => {
  const siLineItems = [];
  let lineCounter = 0;
  let allGdLines = [];
  const plantID = gdListData[0].plant_id;

  for (const gd of gdListData) {
    // Get GD lines
    const gdLines = gd.table_gd || [];

    for (const gdItem of gdLines) {
      // Find matching SO line item
      const soLineItem = findSoLineItem(gdItem, soLineItemList);
      const soData = findSOData(gdItem, soList);

      // A GD line with no SO line behind it (description row) carries no price -- nothing to bill.
      if (!soLineItem || !soData) continue;

      const soQuantity = parseFloat(soLineItem.so_quantity) || 0;
      const alreadyInvoiced = parseFloat(soLineItem.invoice_qty) || 0;
      // What this SO line still allows to be invoiced. SI_SAVE rejects (410) anything above it.
      const remaining = roundQty(soQuantity - alreadyInvoiced);

      let invoiceQty = parseFloat(gdItem.gd_qty) || 0;

      if (isAuto) {
        // Already fully invoiced by an earlier GD on the same SO line -- skip, do not error.
        if (remaining <= 0) continue;
        // Over-delivery beyond the ordered quantity cannot be invoiced against this SO line.
        if (invoiceQty > remaining) invoiceQty = remaining;
        if (invoiceQty <= 0) continue;
      }

      const unitPrice = parseFloat(soLineItem.so_item_price) || 0;
      const discountAmount = parseFloat(soLineItem.so_discount_amount) || 0;
      const taxAmount = parseFloat(soLineItem.so_tax_amount) || 0;
      const totalAmount = parseFloat(soLineItem.so_amount) || 0;

      const ratio = soQuantity > 0 ? invoiceQty / soQuantity : 0;
      const recalculatedGross = unitPrice * invoiceQty;
      const recalculatedDiscountAmount = discountAmount * ratio;
      const recalculatedTaxAmount = taxAmount * ratio;
      const recalculatedAmount = totalAmount * ratio;

      const lineItem = mapLineItem(
        gdItem,
        soLineItem,
        gd,
        lineCounter,
        soData,
        plantID,
        invoiceQty,
      );

      // Store recalculated values for totals calculation
      gdItem.recalculated_gross = recalculatedGross;
      gdItem.recalculated_discount_amount = recalculatedDiscountAmount;
      gdItem.recalculated_tax_amount = recalculatedTaxAmount;
      gdItem.recalculated_amount = recalculatedAmount;
      gdItem.myr_amount =
        recalculatedAmount * (parseFloat(soData.exchange_rate) || 1);

      allGdLines.push(gdItem);
      siLineItems.push(lineItem);
      lineCounter++;
    }
  }

  return { siLineItems, allGdLines };
};

if (isMultiple === "multiple") {
  for (const gdData of gdList) {
    const { siLineItems, allGdLines } = processGdList([gdData]);
    // No billable line -> no SI. mapHeaderData reads lineItemPromise[0], and an empty table_si
    // would be rejected by SI_SAVE anyway (406 required / 407 zero qty).
    if (siLineItems.length === 0) continue;
    const totals = calculateTotalsFromGdLines(allGdLines);
    const soNoDisplay = gdData.so_no;
    const soID = gdData.so_id;
    const gdNoDisplay = gdData.delivery_no;
    const gdID = [gdData.id];
    const mappedData = mapHeaderData(
      gdData,
      siLineItems,
      soNoDisplay,
      soID,
      gdNoDisplay,
      gdID,
      totals,
    );
    siList.push(mappedData);
  }
} else if (isMultiple === "single" && gdList.length > 0) {
  const gdData = gdList[0];
  const { siLineItems, allGdLines } = processGdList(gdList);
  if (siLineItems.length > 0) {
    const totals = calculateTotalsFromGdLines(allGdLines);
    const soNoDisplay = gdList.map((item) => item.so_no).join(", ");
    const soID = gdList.flatMap((gd) => gd.so_id || []);
    const gdNoDisplay = gdList.map((item) => item.delivery_no).join(", ");
    const gdID = gdList.map((item) => item.id);
    const mappedData = mapHeaderData(
      gdData,
      siLineItems,
      soNoDisplay,
      soID,
      gdNoDisplay,
      gdID,
      totals,
    );
    siList.push(mappedData);
  }
}

return { siList, siCount: siList.length };

const userID = {{system:uid}};
const now = new Date();
const date = now.toISOString().split('T')[0]; // YYYY-MM-DD
const time = now.toTimeString().split(' ')[0].replace(/:/g, ''); // HHMMSS

return {
  redis_name: `GD_CONVERT_SI:${userID}:${date}:${time}`
  // Example: "GD_CONVERT_SI:12345:2024-02-24:143022"
};

const currentIndexRaw = {{node:get_cache_node_l03kAFq7.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;
const siList = {{node:code_node_sQX9tldw.data.siList}}
const siData = siList[index];

return {
  siData,
  nextIndex: index + 1
}

// Accumulate what SI_SAVE returned for this iteration. The loop's node outputs are not
// readable once the loop ends, so each result is parked in redis and re-read by code_summary.
//
// SI_SAVE only reaches an OK end-node when the SI was actually written, so an empty id means the
// save did not produce a row. Its failure paths (406/407/410) are ERROR end-nodes that throw
// rather than return -- the auto path is built so they cannot be reached (see 5. Map SI Data).
const raw = {{node:get_cache_results.data}};

let results = [];
if (raw) {
  results = typeof raw === "string" ? JSON.parse(raw) : raw;
}
if (!Array.isArray(results)) results = [];

const siId = {{node:workflow_node_gz6u8DqY.data.id}} || "";
const siNo = {{node:workflow_node_gz6u8DqY.data.si_no}} || "";
const piTriggerFailed = {{node:workflow_node_gz6u8DqY.data.pi_trigger_failed}} || 0;
const piMessage = {{node:workflow_node_gz6u8DqY.data.pi_message}} || "";

results.push({
  si_id: siId ? String(siId) : "",
  si_no: siNo ? String(siNo) : "",
  pi_trigger_failed: Number(piTriggerFailed) || 0,
  pi_message: piMessage,
});

return { results: results };

const raw = {{node:get_cache_final.data}};

let results = [];
if (raw) {
  results = typeof raw === "string" ? JSON.parse(raw) : raw;
}
if (!Array.isArray(results)) results = [];

const created = results.filter((r) => r && r.si_id);
const failed = results.filter((r) => !r || !r.si_id);

// si_id / si_no describe the FIRST invoice created. The auto path always converts exactly one GD,
// so that is the one GDheadWorkflow reports back; a multi-GD convert just uses the counts.
const first = created.length > 0 ? created[0] : null;

let code = "200";
let message = "";

if (created.length === 0) {
  code = "400";
  message = "The Sales Invoice could not be created.";
} else {
  message =
    "Created " +
    created.length +
    " sales invoice" +
    (created.length === 1 ? "" : "s") +
    (failed.length > 0 ? ", " + failed.length + " failed." : ".");
}

// A failed buyer-side PI does not invalidate the SI, which is saved either way -- surface it in the
// message instead of turning a written invoice into a failure.
const piFailed = created.filter((r) => Number(r.pi_trigger_failed) === 1);
if (piFailed.length > 0 && piFailed[0].pi_message) {
  message = message + " " + piFailed[0].pi_message;
}

return {
  code: code,
  message: message,
  si_id: first ? first.si_id : "",
  si_no: first ? first.si_no : "",
  skipped: 0,
};
